sealed class CustomErrorKind: kotlin.Exception() {
    
    /**
     * An entity was not found, often a file.
     */
    class NotFound(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The operation lacked the necessary privileges to complete.
     */
    class PermissionDenied(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The connection was refused by the remote server.
     */
    class ConnectionRefused(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The connection was reset by the remote server.
     */
    class ConnectionReset(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The remote host is not reachable.
     */
    class HostUnreachable(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The network containing the remote host is not reachable.
     */
    class NetworkUnreachable(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The connection was aborted (terminated) by the remote server.
     */
    class ConnectionAborted(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The network operation failed because it was not connected yet.
     */
    class NotConnected(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * A socket address could not be bound because the address is already in use elsewhere.
     */
    class AddrInUse(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * A nonexistent interface was requested or the requested address was not local.
     */
    class AddrNotAvailable(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The system's networking is down.
     */
    class NetworkDown(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The operation failed because a pipe was closed.
     */
    class BrokenPipe(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * An entity already exists, often a file.
     */
    class AlreadyExists(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The operation needs to block to complete, but the blocking operation was
     * requested to not occur.
     */
    class WouldBlock(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * A filesystem object is, unexpectedly, not a directory.
     *
     * For example, a filesystem path was specified where one of the intermediate directory
     * components was, in fact, a plain file.
     */
    class NotADirectory(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The filesystem object is, unexpectedly, a directory.
     *
     * A directory was specified when a non-directory was expected.
     */
    class IsADirectory(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * A non-empty directory was specified where an empty directory was expected.
     */
    class DirectoryNotEmpty(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The filesystem or storage medium is read-only, but a write operation was attempted.
     */
    class ReadOnlyFilesystem(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * Stale network file handle.
     *
     * With some network filesystems, notably NFS, an open file (or directory) can be invalidated
     * by problems with the network or server.
     */
    class StaleNetworkFileHandle(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * A parameter was incorrect.
     */
    class InvalidInput(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * Data not valid for the operation were encountered.
     *
     * Unlike [`InvalidInput`], this typically means that the operation
     * parameters were valid, however the error was caused by malformed
     * input data.
     *
     * For example, a function that reads a file into a string will error with
     * `InvalidData` if the file's contents are not valid UTF-8.
     *
     * [`InvalidInput`]: ErrorKind::InvalidInput
     */
    class InvalidData(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The I/O operation's timeout expired, causing it to be canceled.
     */
    class TimedOut(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * An error returned when an operation could not be completed because a
     * call to [`write`] returned [`Ok(0)`].
     *
     * This typically means that an operation could only succeed if it wrote a
     * particular number of bytes but only a smaller number of bytes could be
     * written.
     *
     * [`write`]: crate::io::Write::write
     * [`Ok(0)`]: Ok
     */
    class WriteZero(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * The underlying storage (typically, a filesystem) is full.
     *
     * This does not include out of quota errors.
     */
    class StorageFull(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * Seek on unseekable file.
     *
     * Seeking was attempted on an open file handle which is not suitable for seeking - for
     * example, on Unix, a named pipe opened with `File::open`.
     */
    class NotSeekable(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * Filesystem quota or some other kind of quota was exceeded.
     */
    class QuotaExceeded(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * File larger than allowed or supported.
     *
     * This might arise from a hard limit of the underlying filesystem or file access API, or from
     * an administratively imposed resource limitation.  Simple disk full, and out of quota, have
     * their own errors.
     */
    class FileTooLarge(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
     * Resource is busy.
     */
    class ResourceBusy(
        ) : CustomErrorKind() {
        override val message
            get() = ""
    }
    
    /**
